"use client";

import { useLayoutEffect, useRef } from "react";
import { historyItems } from "@/data/history";
import styles from "./History.module.css";

export function History() {
  const sectionRef = useRef<HTMLElement | null>(null);
  const trackRef = useRef<HTMLDivElement | null>(null);
  const progressRef = useRef<HTMLDivElement | null>(null);

  useLayoutEffect(() => {
    let ctx: { revert: () => void } | undefined;

    const setup = async () => {
      const gsapModule = await import("gsap");
      const scrollTriggerModule = await import("gsap/ScrollTrigger");
      const gsap = gsapModule.default;
      const ScrollTrigger = scrollTriggerModule.ScrollTrigger;
      gsap.registerPlugin(ScrollTrigger);

      const section = sectionRef.current;
      const track = trackRef.current;
      const progress = progressRef.current;
      if (!section || !track || !progress) return;

      ctx = gsap.context(() => {
        const horizontalTween = gsap.to(track, {
          x: () => -(track.scrollWidth - window.innerWidth),
          ease: "none",
          scrollTrigger: {
            trigger: section,
            start: "top top",
            end: () => `+=${Math.max(0, track.scrollWidth - window.innerWidth)}`,
            scrub: 1,
            pin: true,
            anticipatePin: 1,
            invalidateOnRefresh: true,
            onUpdate: (self) => gsap.set(progress, { scaleX: self.progress }),
          },
        });

        const slides = Array.from(track.querySelectorAll<HTMLElement>("[data-history-slide]"));
        slides.forEach((slide) => {
          const image = slide.querySelector<HTMLElement>("[data-history-image]");
          const content = slide.querySelector<HTMLElement>("[data-history-content]");

          if (image) {
            gsap.fromTo(image, { scale: 1 }, {
              scale: 1.055,
              ease: "none",
              scrollTrigger: {
                trigger: slide,
                containerAnimation: horizontalTween,
                start: "left right",
                end: "right left",
                scrub: true,
              },
            });
          }

          if (content) {
            gsap.fromTo(content, { y: 40, opacity: 0.45 }, {
              y: 0,
              opacity: 1,
              ease: "none",
              scrollTrigger: {
                trigger: slide,
                containerAnimation: horizontalTween,
                start: "left 80%",
                end: "center center",
                scrub: true,
              },
            });
          }
        });
      }, section);
    };

    setup();
    return () => ctx?.revert();
  }, []);

  return (
    <section ref={sectionRef} className={styles.history} aria-labelledby="history-title">
      <div className={styles.topbar}>
        <div>
          <span className={styles.kicker}>Nossa história</span>
          <h2 id="history-title" className={styles.heading}>
            Uma cooperativa que cresce junto com a comunidade.
          </h2>
        </div>
        <p className={styles.intro}>
          Role para acompanhar alguns dos capítulos que ajudaram a construir a Coopercica.
        </p>
      </div>

      <div ref={trackRef} className={styles.track}>
        {historyItems.map((item, index) => (
          <article key={item.id} data-history-slide className={`${styles.slide} ${styles[item.theme]}`}>
            <div className={styles.yearWatermark} aria-hidden="true">{item.year}</div>
            <div className={styles.media}>
              <img
                data-history-image
                src={item.image}
                alt={item.imageAlt}
                className={styles.image}
                loading={index < 2 ? "eager" : "lazy"}
              />
            </div>
            <div data-history-content className={styles.content}>
              <span className={styles.eyebrow}>{item.eyebrow}</span>
              <strong className={styles.year}>{item.year}</strong>
              <h3>{item.title}</h3>
              <p>{item.description}</p>
              <span className={styles.counter}>
                {String(index + 1).padStart(2, "0")} / {String(historyItems.length).padStart(2, "0")}
              </span>
            </div>
          </article>
        ))}
      </div>

      <div className={styles.progressShell} aria-hidden="true">
        <div ref={progressRef} className={styles.progress} />
      </div>
    </section>
  );
}
